import java.io.*;
import java.util.*;

public class Main {
    private static boolean isPossible(int[] books, int n, int m, long limit) {
        int students = 1;
        long sum = 0;
        for (int i = 0; i < n; i++) {
            if (books[i] > limit) return false;
            if (sum + books[i] > limit) {
                students++;
                sum = books[i];
                if (students > m) return false;
            } else {
                sum += books[i];
            }
        }
        return true;
    }

    private static long allocateBooks(int[] books, int n, int m) {
        if (m > n) return -1;
        long low = 0, high = 0;
        for (int v : books) {
            low = Math.max(low, v);
            high += v;
        }
        long ans = -1;
        while (low <= high) {
            long mid = low + (high - low) / 2;
            if (isPossible(books, n, m, mid)) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            int[] books = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) {
                books[i] = Integer.parseInt(st.nextToken());
            }
            out.append(allocateBooks(books, N, M)).append('\n');
        }
        System.out.print(out.toString());
    }
}

